import type { NordicCoreContext } from '../common/types';

import { AsyncLocalStorage } from 'node:async_hooks';

import { isTestEnv } from '@nordic/utils/validation';

import { throwContextNotInitializedError } from '../common/error';
import { getTestContextScope } from '../common/scope';

export type NordicCoreServerContext = NordicCoreContext & {
  layoutMiddlewareOptions?: unknown;
};

export const storage = new AsyncLocalStorage<NordicCoreServerContext>();

export function getContext() {
  const context = storage.getStore();

  if (!__DEV__) {
    return context!;
  }

  if (isTestEnv()) {
    return getTestContextScope().c! as NordicCoreServerContext;
  }

  if (!context) {
    throwContextNotInitializedError();
  }

  return context;
}
